// src/Sidebar.js
import React from "react";
import {
  Home,
  Calendar,
  BookOpen,
  Users,
  User,
  Mail,
  Settings,
  HelpCircle
} from "lucide-react";

// Recebe active e onMenuClick por props
const menuItems = [
  {
    label: "Dashboard",
    icon: <Home size={22} />,
    key: "dashboard",
  },
  {
    label: "Agendar Paciente",
    icon: <Calendar size={22} />,
    key: "agendar",
  },
  {
    label: "Disciplinas",
    icon: <BookOpen size={22} />,
    key: "disciplinas",
  },
  {
    label: "Pacientes",
    icon: <Users size={22} />,
    key: "pacientes",
  },
  {
    label: "Alunos",
    icon: <User size={22} />,
    key: "alunos",
  },
  {
    label: "Solicitações",
    icon: <Mail size={22} />,
    key: "solicitacoes",
  },
];

const bottomItems = [
  {
    label: "Configurações",
    icon: <Settings size={22} />,
    key: "config",
  },
  {
    label: "Ajuda",
    icon: <HelpCircle size={22} />,
    key: "ajuda",
  },
];

export default function Sidebar({ active, onMenuClick }) {
  return (
    <aside className="fixed top-16 left-0 z-40 flex flex-col justify-between w-64 h-[calc(100vh-4rem)] bg-white border-r shadow-sm">
      <div>
        <nav className="mt-4">
          <ul>
            {menuItems.map((item) => (
              <li key={item.key} className="mb-1">
                <button
                  className={`flex items-center w-full px-5 py-3 text-base font-medium rounded-full transition-colors
                    ${
                      active === item.key
                        ? "bg-indigo-100 text-gray-900 font-bold"
                        : "hover:bg-gray-100 text-gray-700"
                    }
                  `}
                  onClick={() => onMenuClick(item.key)}
                >
                  <span className="mr-3">{item.icon}</span>
                  {item.label}
                </button>
              </li>
            ))}
          </ul>
        </nav>
      </div>
      <div className="mb-8">
        <ul>
          {bottomItems.map((item) => (
            <li key={item.key} className="mb-2">
              <button
                className="flex items-center w-full px-5 py-2 text-base font-medium text-gray-700 hover:bg-gray-100 rounded-full transition-colors"
                onClick={() => onMenuClick(item.key)}
              >
                <span className="mr-3">{item.icon}</span>
                {item.label}
              </button>
            </li>
          ))}
        </ul>
      </div>
    </aside>
  );
}
